/**
 * Performance Tracking Utility Tests
 *
 * Tests for the performance tracking wrapper that standardizes timing capture
 * and context updates across all 9 classification pipeline stages.
 */

import { trackStagePerformance } from '../../src/utils/performance-tracking';
import { ClassificationContext } from '../../src/stages/types';

describe('Performance Tracking Utility', () => {
  let context: ClassificationContext;

  beforeEach(() => {
    context = {
      candidateScores: {},
      rejectedCategories: [],
      stageTimings: {},
      configurationRefs: {},
      selectedAttributes: [],
      detectedAttributes: [],
      featureExtractionPrompts: [],
      classificationPrompts: [],
    };
  });

  describe('Basic Timing Capture', () => {
    it('should capture timing for synchronous operations', () => {
      const result = trackStagePerformance('test_stage', 'config.test.path', context, () => {
        // Simulate work
        const start = Date.now();
        while (Date.now() - start < 10) {
          // Busy wait for ~10ms
        }
        return { success: true };
      });

      expect(result.success).toBe(true);
      expect(context.stageTimings['test_stage']).toBeGreaterThanOrEqual(10);
      expect(context.stageTimings['test_stage']).toBeLessThan(100);
      expect(context.configurationRefs['test_stage']).toBe('config.test.path');
    });

    it('should capture timing for async operations', async () => {
      const result = await trackStagePerformance('async_stage', 'config.async.path', context, async () => {
        await new Promise((resolve) => setTimeout(resolve, 20));
        return { success: true };
      });

      expect(result.success).toBe(true);
      expect(context.stageTimings['async_stage']).toBeGreaterThanOrEqual(20);
      expect(context.stageTimings['async_stage']).toBeLessThan(100);
      expect(context.configurationRefs['async_stage']).toBe('config.async.path');
    });

    it('should return exact result from wrapped function', () => {
      const expectedResult = {
        categories: ['test1', 'test2'],
        scores: { test1: 0.9, test2: 0.8 },
        metadata: { key: 'value' },
      };

      const result = trackStagePerformance('result_test', 'config.path', context, () => expectedResult);

      expect(result).toEqual(expectedResult);
    });

    it('should preserve return type for async functions', async () => {
      interface AsyncResult {
        data: string[];
        count: number;
      }

      const result = await trackStagePerformance(
        'typed_async',
        'config.path',
        context,
        async (): Promise<AsyncResult> => {
          return { data: ['a', 'b'], count: 2 };
        }
      );

      expect(result.data).toEqual(['a', 'b']);
      expect(result.count).toBe(2);
    });
  });

  describe('Context Updates', () => {
    it('should update context.stageTimings with accurate duration', () => {
      trackStagePerformance('timing_update', 'config.path', context, () => {
        return {};
      });

      expect(context.stageTimings['timing_update']).toBeDefined();
      expect(typeof context.stageTimings['timing_update']).toBe('number');
      expect(context.stageTimings['timing_update']).toBeGreaterThanOrEqual(0);
    });

    it('should update context.configurationRefs with config path', () => {
      trackStagePerformance('config_update', 'category_signals.*.hard_assertions', context, () => {
        return {};
      });

      expect(context.configurationRefs['config_update']).toBe('category_signals.*.hard_assertions');
    });

    it('should handle multiple stage executions without overwriting', () => {
      trackStagePerformance('stage1', 'config.stage1', context, () => ({}));
      trackStagePerformance('stage2', 'config.stage2', context, () => ({}));
      trackStagePerformance('stage3', 'config.stage3', context, () => ({}));

      expect(Object.keys(context.stageTimings)).toHaveLength(3);
      expect(Object.keys(context.configurationRefs)).toHaveLength(3);
      expect(context.stageTimings['stage1']).toBeDefined();
      expect(context.stageTimings['stage2']).toBeDefined();
      expect(context.stageTimings['stage3']).toBeDefined();
      expect(context.configurationRefs['stage1']).toBe('config.stage1');
      expect(context.configurationRefs['stage2']).toBe('config.stage2');
      expect(context.configurationRefs['stage3']).toBe('config.stage3');
    });

    it('should allow same stage to be re-executed with updated timing', () => {
      trackStagePerformance('reexecuted_stage', 'config.path', context, () => {
        const start = Date.now();
        while (Date.now() - start < 5) {}
        return {};
      });

      const firstTiming = context.stageTimings['reexecuted_stage'];

      trackStagePerformance('reexecuted_stage', 'config.path', context, () => {
        const start = Date.now();
        while (Date.now() - start < 15) {}
        return {};
      });

      const secondTiming = context.stageTimings['reexecuted_stage'];

      expect(secondTiming).toBeGreaterThan(firstTiming);
    });
  });

  describe('Error Handling', () => {
    it('should propagate errors from wrapped function', () => {
      expect(() => {
        trackStagePerformance('error_stage', 'config.path', context, () => {
          throw new Error('Stage execution failed');
        });
      }).toThrow('Stage execution failed');
    });

    it('should still update context even when function throws', () => {
      try {
        trackStagePerformance('error_with_context', 'config.error.path', context, () => {
          throw new Error('Test error');
        });
      } catch (error) {
        // Expected error
      }

      // Context should still be updated with timing and config ref
      expect(context.stageTimings['error_with_context']).toBeDefined();
      expect(context.configurationRefs['error_with_context']).toBe('config.error.path');
    });

    it('should propagate async errors', async () => {
      await expect(
        trackStagePerformance('async_error', 'config.path', context, async () => {
          await new Promise((_, reject) => setTimeout(() => reject(new Error('Async failure')), 10));
        })
      ).rejects.toThrow('Async failure');
    });

    it('should update context before async error propagation', async () => {
      try {
        await trackStagePerformance('async_error_context', 'config.async.error', context, async () => {
          await new Promise((_, reject) => setTimeout(() => reject(new Error('Async error')), 10));
        });
      } catch (error) {
        // Expected error
      }

      expect(context.stageTimings['async_error_context']).toBeDefined();
      expect(context.configurationRefs['async_error_context']).toBe('config.async.error');
    });
  });

  describe('Timing Accuracy', () => {
    it('should have minimal overhead (< 1ms variance)', () => {
      const targetDelay = 50;

      const result = trackStagePerformance('accuracy_test', 'config.path', context, () => {
        const start = Date.now();
        while (Date.now() - start < targetDelay) {}
        return { duration: Date.now() - start };
      });

      const measuredDuration = context.stageTimings['accuracy_test'];
      const variance = Math.abs(measuredDuration - targetDelay);

      expect(variance).toBeLessThan(5); // Allow 5ms variance for system scheduling
    });

    it('should measure fast operations accurately', () => {
      trackStagePerformance('fast_operation', 'config.path', context, () => {
        return { result: 'immediate' };
      });

      expect(context.stageTimings['fast_operation']).toBeGreaterThanOrEqual(0);
      expect(context.stageTimings['fast_operation']).toBeLessThan(10);
    });

    it('should measure slow operations accurately', async () => {
      const targetDelay = 100;

      await trackStagePerformance('slow_operation', 'config.path', context, async () => {
        await new Promise((resolve) => setTimeout(resolve, targetDelay));
        return {};
      });

      expect(context.stageTimings['slow_operation']).toBeGreaterThanOrEqual(targetDelay);
      expect(context.stageTimings['slow_operation']).toBeLessThan(targetDelay + 50);
    });
  });

  describe('Real Pipeline Stage Patterns', () => {
    it('should handle hard assertions stage pattern', () => {
      const result = trackStagePerformance('hard_assertions', 'category_signals.*.hard_assertions', context, () => {
        const categoriesWithHardAssertions: string[] = ['FINANCE'];
        const assertionResults = [{ category: 'FINANCE', assertionType: 'domain', matched: true }];

        return {
          categoriesWithHardAssertions,
          assertionResults,
          updatedScores: { FINANCE: 1.0 },
        };
      });

      expect(result.categoriesWithHardAssertions).toEqual(['FINANCE']);
      expect(context.stageTimings['hard_assertions']).toBeDefined();
      expect(context.configurationRefs['hard_assertions']).toBe('category_signals.*.hard_assertions');
    });

    it('should handle attribute detection stage pattern', () => {
      const result = trackStagePerformance('attribute_detection', 'attributes.detectors', context, () => {
        return {
          detectedAttributes: ['urgent', 'from_important_sender'],
          attributeScores: { urgent: 1.0, from_important_sender: 0.9 },
        };
      });

      expect(result.detectedAttributes).toHaveLength(2);
      expect(context.stageTimings['attribute_detection']).toBeDefined();
    });

    it('should handle AI routing stage pattern', async () => {
      const result = await trackStagePerformance('ai_routing', 'confidence_thresholds', context, async () => {
        await new Promise((resolve) => setTimeout(resolve, 10)); // Simulate AI call
        return {
          requiresAI: true,
          confidence: 0.65,
          routing: 'ai_classification_required',
        };
      });

      expect(result.requiresAI).toBe(true);
      expect(context.stageTimings['ai_routing']).toBeGreaterThanOrEqual(10);
    });
  });

  describe('Type Safety', () => {
    it('should enforce correct stage name type', () => {
      // This test validates TypeScript compilation
      const stageName: string = 'test_stage';
      trackStagePerformance(stageName, 'config.path', context, () => ({}));
      expect(context.stageTimings[stageName]).toBeDefined();
    });

    it('should enforce correct config path type', () => {
      const configPath: string = 'config.test.path';
      trackStagePerformance('test', configPath, context, () => ({}));
      expect(context.configurationRefs['test']).toBe(configPath);
    });

    it('should preserve function return type inference', () => {
      interface StageResult {
        categories: string[];
        scores: Record<string, number>;
      }

      const result: StageResult = trackStagePerformance('typed_stage', 'config.path', context, (): StageResult => {
        return {
          categories: ['A', 'B'],
          scores: { A: 0.9, B: 0.8 },
        };
      });

      expect(result.categories).toEqual(['A', 'B']);
      expect(result.scores).toEqual({ A: 0.9, B: 0.8 });
    });
  });
});

